import{_ as e,o as a,c as i,ao as s}from"./chunks/framework.gRc-vvNE.js";const o="/Fromage.jl/previews/PR39/assets/tracking-run.P_0kPd7f.webp",r="/Fromage.jl/previews/PR39/assets/diagnostic-dappled.DRrX4ODD.png",k=JSON.parse('{"title":"Your results","description":"","frontmatter":{},"headers":[],"relativePath":"results.md","filePath":"results.md","lastUpdated":null}'),n={name:"results.md"};function l(d,t,h,c,p,g){return a(),i("div",null,[...t[0]||(t[0]=[s('<h1 id="Your-results" tabindex="-1">Your results <a class="header-anchor" href="#Your-results" aria-label="Permalink to &quot;Your results {#Your-results}&quot;">​</a></h1><p>When <code>main</code> finishes, you have two kinds of output: <strong>files on disk</strong> (in a <code>results_dir</code> folder, created in the folder Julia was started in) and, if you&#39;re working in Julia, a <strong>DataFrame</strong> returned by <code>main</code>. Most people only need the files.</p><h2 id="The-track-files" tabindex="-1">The track files <a class="header-anchor" href="#The-track-files" aria-label="Permalink to &quot;The track files {#The-track-files}&quot;">​</a></h2><p>Each run&#39;s track is written to <code>results_dir/&lt;run_id&gt;.csv</code> — a plain csv you can open in Excel, R, Python, MATLAB, or anything else. It has three columns:</p><table tabindex="0"><thead><tr><th style="text-align:right;">column</th><th style="text-align:right;">content</th></tr></thead><tbody><tr><td style="text-align:right;"><code>time</code></td><td style="text-align:right;">the timestamp, in seconds into the video, of each detected coordinate.</td></tr><tr><td style="text-align:right;"><code>x</code>, <code>y</code></td><td style="text-align:right;">the target&#39;s <strong>real-world</strong> coordinates at that time.</td></tr></tbody></table><p>The coordinates are already fully converted — lens distortion, perspective, and scale are all corrected:</p><ul><li><p>The <strong>origin</strong> (0, 0) is at the calibration&#39;s <code>center</code> (if you gave one).</p></li><li><p>If you gave a <code>north</code> point, the coordinates are rotated so north is consistent across calibrations.</p></li><li><p>The <strong>unit</strong> is whatever your calibration used: the <code>checker_size</code> unit for checkerboard and AprilTag calibrations (e.g. cm if you measured your squares in cm), the <code>scale</code> unit for <code>only_scale</code>, or the MATLAB calibration&#39;s unit for <code>matlab</code>.</p></li><li><p><code>x</code> grows rightward and <code>y</code> grows <strong>downward</strong> in the image, like the pixel convention.</p></li></ul><h2 id="The-diagnostic-video" tabindex="-1">The diagnostic video <a class="header-anchor" href="#The-diagnostic-video" aria-label="Permalink to &quot;The diagnostic video {#The-diagnostic-video}&quot;">​</a></h2><p><code>main</code> also writes <code>results_dir/diagnostic.mp4</code>: every run rendered top-down through its calibration into a fixed 540×540 canvas, with a circle around the tracked position, a trailing trace, and the video&#39;s file name as a label — one run after the other, playing at 2× real time (≈24 fps regardless of the tracking fps).</p><p>This is what a healthy run looks like — the circle sits on the animal for the whole run, and the trace grows behind it from the centre of the arena to the edge (one complete run, looping):</p><p><img src="'+o+'" alt=""></p><p>And the same check works in harder conditions. Here the arena is covered in dappled light, yet the circle should still follow the animal — if it jumps to a bright patch instead, you&#39;ve caught a bad track:</p><p><img src="'+r+`" alt=""></p><div class="danger custom-block"><p class="custom-block-title">Watch it!</p><p>The diagnostic video is the fastest way to catch a tracker that latched onto a shadow, a wrong starting position, or a bad calibration. Watch it before analysing any tracks.</p></div><p>Things to look for:</p><ul><li><p>The circle should stay on your animal for the whole run — not jump to a shadow, a droppings mark, or a cable.</p></li><li><p>The arena should look right in the top-down view: straight edges straight, circles circular. A warped arena means a bad calibration.</p></li><li><p>The trace should look like a plausible path for your animal.</p></li></ul><h2 id="Working-with-the-results-in-Julia" tabindex="-1">Working with the results in Julia <a class="header-anchor" href="#Working-with-the-results-in-Julia" aria-label="Permalink to &quot;Working with the results in Julia {#Working-with-the-results-in-Julia}&quot;">​</a></h2><p><code>main</code> returns a <code>DataFrame</code> with one row per run:</p><table tabindex="0"><thead><tr><th style="text-align:right;">column</th><th style="text-align:right;">content</th></tr></thead><tbody><tr><td style="text-align:right;"><code>run_id</code>, <code>calibration_id</code></td><td style="text-align:right;">the identifiers from the csv files.</td></tr><tr><td style="text-align:right;"><code>run</code></td><td style="text-align:right;">the track: a tuple <code>(ts, coords)</code> of timestamps (seconds into the video) and the target&#39;s <strong>real-world</strong> coordinates — the same data as the track file.</td></tr><tr><td style="text-align:right;"><code>rectification</code></td><td style="text-align:right;">the calibration: a named tuple whose <code>image2real</code> function converts pixel coordinates to real-world coordinates; <code>real2image</code> is its inverse.</td></tr><tr><td style="text-align:right;"><code>r</code>, <code>c</code></td><td style="text-align:right;">the parsed run and calibration entries (all the resolved parameter values).</td></tr></tbody></table><p>For example:</p><div class="language-julia vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">julia</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">runs </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> main</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;path/to/data&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">ts, xy </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> runs</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">.</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">run[</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">1</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">]    </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># first run: timestamps + real-world coordinates (e.g. cm)</span></span></code></pre></div>`,21)])])}const m=e(n,[["render",l]]);export{k as __pageData,m as default};
